function a(t,n="0"){if(t==null||t==="")return n;const r=Number(t);return Number.isNaN(r)?String(t):r.toFixed(1).replace(/\.0$/,"")}function f(t){if(t==null||t==="")return null;const n=Number(t);return Number.isNaN(n)?null:Math.abs(n)>10?n/10:n}function u(t,n="-"){const r=f(t);return r===null?n:r.toFixed(1).replace(".",",")}function s(t,n="-"){if(t==null||t==="")return n;if(typeof t=="string"){const e=t.match(/^(\d{4})-(\d{2})-(\d{2})/);if(e)return`${e[3]}/${e[2]}`}const r=t instanceof Date?t:new Date(t);if(Number.isNaN(r.getTime()))return String(t);const i=String(r.getDate()).padStart(2,"0"),o=String(r.getMonth()+1).padStart(2,"0");return`${i}/${o}`}export{a,s as b,u as f,f as n};
